'use client'

import { useRouter } from 'next/navigation'
import { useEffect, useState } from 'react'
import GovNavbar from '@/components/government/navbar'
import FeedbackCard from '@/components/government/feedback-card'
import { Button } from '@/components/ui/button'
import { Empty } from '@/components/ui/empty'
import { Skeleton } from '@/components/ui/skeleton'
import { ArrowLeft } from 'lucide-react'

export default function FeedbackPage() {
  const router = useRouter()
  const [feedback, setFeedback] = useState<any[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    // TODO: Replace with actual API call to fetch citizen feedback
    const fetchFeedback = async () => {
      try {
        setIsLoading(true)
        // Simulate API delay
        await new Promise(resolve => setTimeout(resolve, 500))
        // TODO: Fetch from /api/feedback or similar
        setFeedback([])
      } catch (err) {
        setError('Failed to load feedback')
      } finally {
        setIsLoading(false)
      }
    }

    fetchFeedback()
  }, [])

  return (
    <div className="min-h-screen bg-background">
      <GovNavbar governmentName="Government Official" />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 py-8">
        {/* Header with back button */}
        <div className="mb-8">
          <Button
            variant="ghost"
            onClick={() => router.back()}
            className="mb-4 text-muted-foreground hover:text-foreground gap-2"
          >
            <ArrowLeft className="w-4 h-4" />
            Back
          </Button>
          <h1 className="text-3xl font-bold text-foreground mb-2">Citizen Feedback</h1>
          <p className="text-muted-foreground">
            Reviews and ratings from citizens about government responses
          </p>
        </div>

        {/* Filters (Optional) */}
        <div className="mb-6 flex flex-wrap gap-2">
          <Button variant="outline" size="sm" className="border-border hover:bg-secondary">
            All Ratings
          </Button>
          <Button variant="outline" size="sm" className="border-border hover:bg-secondary">
            5 Stars
          </Button>
          <Button variant="outline" size="sm" className="border-border hover:bg-secondary">
            Recent
          </Button>
        </div>

        {/* Content */}
        {error ? (
          <Empty
            icon="alert-circle"
            title="Error loading feedback"
            description="Failed to load citizen feedback. Please try again."
          />
        ) : isLoading ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {Array.from({ length: 6 }).map((_, i) => (
              <Skeleton key={i} className="h-48 bg-secondary rounded-lg" />
            ))}
          </div>
        ) : feedback.length === 0 ? (
          <Empty
            icon="message-square"
            title="No feedback yet"
            description="Citizen feedback will appear here once they provide reviews"
          />
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {feedback.map((item) => (
              <FeedbackCard key={item.id} feedback={item} />
            ))}
          </div>
        )}
      </main>
    </div>
  )
}
